import React, { useState, useMemo } from 'react';
import { Search, Filter, ChevronDown, ChevronUp } from 'lucide-react';
import { AnnouncementCard } from './AnnouncementCard';
import './AnnouncementList.css';

/**
 * AnnouncementList Component
 * Displays list of announcements with filtering and search
 */
export function AnnouncementList({
  announcements = [],
  onEdit,
  onDelete,
  onPin,
  onTogglePublish,
  isAdmin = false,
  compact = false
}) {
  const [searchQuery, setSearchQuery] = useState('');
  const [priorityFilter, setPriorityFilter] = useState('All');
  const [audienceFilter, setAudienceFilter] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');
  const [sortBy, setSortBy] = useState('date-desc');
  const [showFilters, setShowFilters] = useState(false);

  // Filter and sort announcements
  const filteredAnnouncements = useMemo(() => {
    let filtered = [...announcements];

    // Text search
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.filter(ann =>
        ann.title.toLowerCase().includes(query) ||
        ann.description.toLowerCase().includes(query)
      );
    }

    // Priority filter
    if (priorityFilter !== 'All') {
      filtered = filtered.filter(ann => ann.priority === priorityFilter);
    }

    // Audience filter
    if (audienceFilter !== 'All') {
      filtered = filtered.filter(ann => ann.audience === audienceFilter);
    }

    // Status filter
    if (statusFilter !== 'All') {
      if (statusFilter === 'Published') {
        filtered = filtered.filter(ann => ann.isPublished);
      } else if (statusFilter === 'Draft') {
        filtered = filtered.filter(ann => !ann.isPublished);
      } else if (statusFilter === 'Expired') {
        filtered = filtered.filter(ann =>
          ann.expiryDate && new Date(ann.expiryDate) < new Date()
        );
      }
    }

    // Sort
    filtered.sort((a, b) => {
      switch (sortBy) {
        case 'date-desc':
          return new Date(b.publishDate) - new Date(a.publishDate);
        case 'date-asc':
          return new Date(a.publishDate) - new Date(b.publishDate);
        case 'title-asc':
          return a.title.localeCompare(b.title);
        case 'title-desc':
          return b.title.localeCompare(a.title);
        case 'pinned-first':
          return (b.isPinned ? 1 : 0) - (a.isPinned ? 1 : 0);
        default:
          return 0;
      }
    });

    // Pinned announcements at top if sorting by date
    if (sortBy.startsWith('date') || sortBy === 'pinned-first') {
      const pinned = filtered.filter(ann => ann.isPinned);
      const unpinned = filtered.filter(ann => !ann.isPinned);
      filtered = [...pinned, ...unpinned];
    }

    return filtered;
  }, [announcements, searchQuery, priorityFilter, audienceFilter, statusFilter, sortBy]);

  const handleReset = () => {
    setSearchQuery('');
    setPriorityFilter('All');
    setAudienceFilter('All');
    setStatusFilter('All');
    setSortBy('date-desc');
  };

  if (compact) {
    return (
      <div className="announcement-list compact">
        {filteredAnnouncements.length === 0 ? (
          <div className="empty-state">
            <p>No announcements yet</p>
          </div>
        ) : (
          filteredAnnouncements.slice(0, 5).map(ann => (
            <AnnouncementCard
              key={ann.id}
              announcement={ann}
              onEdit={onEdit}
              onDelete={onDelete}
              onPin={onPin}
              onTogglePublish={onTogglePublish}
              isAdmin={isAdmin}
              compact={true}
            />
          ))
        )}
      </div>
    );
  }

  return (
    <div className="announcement-list">
      {/* Header */}
      <div className="list-header">
        <div className="header-title">
          <h2>Announcements {filteredAnnouncements.length > 0 && `(${filteredAnnouncements.length})`}</h2>
          <button
            className="toggle-filters"
            onClick={() => setShowFilters(!showFilters)}
            title="Toggle filters"
          >
            <Filter size={20} />
            {showFilters ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
          </button>
        </div>
      </div>

      {/* Search and Filters */}
      {showFilters && (
        <div className="filters-section">
          {/* Search */}
          <div className="search-box">
            <Search size={18} />
            <input
              type="text"
              placeholder="Search announcements..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="search-input"
            />
            {searchQuery && (
              <button
                className="clear-btn"
                onClick={() => setSearchQuery('')}
              >
                ✕
              </button>
            )}
          </div>

          {/* Filters Grid */}
          <div className="filters-grid">
            {/* Priority Filter */}
            <div className="filter-group">
              <label htmlFor="priority-filter">Priority</label>
              <select
                id="priority-filter"
                value={priorityFilter}
                onChange={(e) => setPriorityFilter(e.target.value)}
                className="filter-select"
              >
                <option value="All">All Priorities</option>
                <option value="Low">Low</option>
                <option value="Normal">Normal</option>
                <option value="Important">Important</option>
                <option value="Urgent">Urgent</option>
              </select>
            </div>

            {/* Audience Filter */}
            <div className="filter-group">
              <label htmlFor="audience-filter">Audience</label>
              <select
                id="audience-filter"
                value={audienceFilter}
                onChange={(e) => setAudienceFilter(e.target.value)}
                className="filter-select"
              >
                <option value="All">All Audiences</option>
                <option value="All Users">All Users</option>
                <option value="Students">Students</option>
                <option value="Teachers">Teachers</option>
                <option value="Parents">Parents</option>
                <option value="Staff">Staff</option>
              </select>
            </div>

            {/* Status Filter */}
            {isAdmin && (
              <div className="filter-group">
                <label htmlFor="status-filter">Status</label>
                <select
                  id="status-filter"
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                  className="filter-select"
                >
                  <option value="All">All Status</option>
                  <option value="Published">Published</option>
                  <option value="Draft">Draft</option>
                  <option value="Expired">Expired</option>
                </select>
              </div>
            )}

            {/* Sort */}
            <div className="filter-group">
              <label htmlFor="sort-by">Sort By</label>
              <select
                id="sort-by"
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="filter-select"
              >
                <option value="date-desc">Newest First</option>
                <option value="date-asc">Oldest First</option>
                <option value="title-asc">Title (A-Z)</option>
                <option value="title-desc">Title (Z-A)</option>
                <option value="pinned-first">Pinned First</option>
              </select>
            </div>
          </div>

          {/* Reset Button */}
          {(searchQuery || priorityFilter !== 'All' || audienceFilter !== 'All' || statusFilter !== 'All') && (
            <button className="reset-btn" onClick={handleReset}>
              Clear All Filters
            </button>
          )}
        </div>
      )}

      {/* Announcements List */}
      <div className="announcements-container">
        {filteredAnnouncements.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">📢</div>
            <h3>No announcements found</h3>
            <p>
              {searchQuery
                ? 'Try adjusting your search terms'
                : 'No announcements match your filters'}
            </p>
          </div>
        ) : (
          <div className="announcements-grid">
            {filteredAnnouncements.map(ann => (
              <AnnouncementCard
                key={ann.id}
                announcement={ann}
                onEdit={onEdit}
                onDelete={onDelete}
                onPin={onPin}
                onTogglePublish={onTogglePublish}
                isAdmin={isAdmin}
                compact={false}
              />
            ))}
          </div>
        )}
      </div>

      {/* Results Info */}
      {filteredAnnouncements.length > 0 && (
        <div className="results-info">
          Showing {filteredAnnouncements.length} of {announcements.length} announcements
        </div>
      )}
    </div>
  );
}
